const TYPES = {
    DEFAULT: 0,
    SELFLEARNING: 1,
    SLOTBOOKING: 2,
};

/**
 * Synchronize hidden flags from selected option type.
 */
const syncFlags = () => {
    const typeSelect = document.querySelector('select[name="optiontype"]');
    const selfLearningInput = document.querySelector('input[name="selflearningcourse"]');
    const slotEnabledInput = document.querySelector('input[name="slot_enabled"]');

    if (!typeSelect || !selfLearningInput || !slotEnabledInput) {
        return;
    }

    const selectedType = Number(typeSelect.value || TYPES.DEFAULT);
    selfLearningInput.value = selectedType === TYPES.SELFLEARNING ? '1' : '0';
    slotEnabledInput.value = selectedType === TYPES.SLOTBOOKING ? '1' : '0';

    selfLearningInput.dispatchEvent(new Event('change', {bubbles: true}));
    slotEnabledInput.dispatchEvent(new Event('change', {bubbles: true}));
};

/**
 * Init option type synchronization.
 */
export const init = () => {
    const typeSelect = document.querySelector('select[name="optiontype"]');
    if (!typeSelect) {
        return;
    }

    typeSelect.addEventListener('change', syncFlags);
    syncFlags();
};
